---resq
function ModelGuildHolyPeak:GuildPinnacleStageResp(pb)
    self.startTime = pb.starTime
    self.endTime = pb.endTime
    self.stage = pb.stage
    self.stageEndTime = pb.stageEndTime
    self.cross = pb.cross

    if updateGuild[self.stage] then
        self:GuildPinnacleGuildInfoReq()
    end
    FireEvent("GuildPinnacleStageResp")
end

function ModelGuildHolyPeak:GuildPinnacleGuildInfoResp(pb)
    self.guildInfoList = {}
    self.isJoin = false
    for _, v in ipairs(pb.guildInfo) do
        local t = {
            guildId = v.guildId,
            guildName = v.guildName,
            flagId = v.flagId,
            guildPower = v.guildPower,
            level = v.level,
            flagBgId = v.flagBgId,
            serverId = v.serverId,
            rank = v.rank
        }
        table.insert(self.guildInfoList, t)

        local guildId = gModelPlayer:GetGuildId()
        if guildId == v.guildId then
            self.isJoin = true
        end
    end

    FireEvent("GuildPinnacleGuildInfoResp")
end

function ModelGuildHolyPeak:GuildPinnacleMatchInfoResp(pb)
    self.matchInfo = {}
    for _, v in ipairs(pb.matchInfo) do
        if not self.matchInfo[v.round] then
            self.matchInfo[v.round] = {}
        end
        for _, v2 in ipairs(v.war) do
            local t = {
                id = v2.id,
                guildA = v2.guildA,
                guildB = v2.guildB,
                winGuild = v2.winGuild,
                third = v2.third,
            }
            table.insert(self.matchInfo[v.round], t)
        end
    end

    FireEvent("GuildPinnacleMatchInfoResp")
end

function ModelGuildHolyPeak:GuildPinnacleCombatProfilesResp(pb)
    self.reportList = {}
    for _, v in ipairs(pb.wars) do
        local t = {
            id = v.id,
            guildA = v.guildA,
            guildB = v.guildB,
            winGuild = v.winGuild,
            third = v.third,
        }
        table.insert(self.reportList, t)
    end

    FireEvent("GuildPinnacleCombatProfilesResp")
end

function ModelGuildHolyPeak:GuildPinnacleFightResultResp(pb)
    local t = {
        id = pb.id,
        winGuild = pb.winGuild
    }
    FireEvent("GuildPinnacleFightResultResp", t)
end

function ModelGuildHolyPeak:GuildPinnacleQuizInfoResp(pb)
    local num = pb.quizItem
    if not num or num == 0 then
        if gLGameUI:FindWndByName("UIGdHoFightPk") then
            GF.OpenWnd("UIGdHoFightPkGuess", { pb = pb })
        else
            if not self.isOpenPeak and gLGameUI:IsJustMain() then
                local func = function()
                    GF.OpenWnd("UIGdWin")
                    GF.OpenWnd("UIGdHoFightPk")
                    GF.OpenWnd("UIGdHoFightPkGuess")
                end
                gModelGeneral:OpenUIOrdinTips({
                    refId = 100205,
                    func = func,
                    itemList = LUtil.GetRefItemDataList(GameTable.ClanWarConfigRef.guildPeakShowReward)
                })
            end
        end
    end
end

